import { ethers } from "hardhat";

async function main() {
  const callData = "";

  // ABI of Safe7579 execution
  const safe7579Abi = [
    "function execute(bytes32 mode, bytes calldata executionCalldata) external"
  ];
  
  const iface = new ethers.Interface(safe7579Abi);
  const parsed = iface.decodeFunctionData("execute", callData);
  console.log("Mode:", parsed[0]);
  console.log("ExecutionCalldata length:", parsed[1].length);

  // ExecutionCalldata encoding depends on mode.
  // For MODE_BATCH, it's a tuple[] (target, value, callData)
  // Let's decode it.
  const batchAbi = [
    "tuple(address target, uint256 value, bytes callData)[]"
  ];
  const decodedCalls = ethers.AbiCoder.defaultAbiCoder().decode(
    batchAbi,
    parsed[1]
  )[0];

  console.log("Decoded batch calls:");
  for (let i = 0; i < decodedCalls.length; i++) {
    const call = decodedCalls[i];
    console.log(`Call ${i}:`);
    console.log("  Target:", call.target);
    console.log("  Value:", call.value.toString());
    console.log("  Calldata:", call.callData);
  }
}

main().catch(console.error);
